import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjTabBar } from "./OjTabBar";
export { OjTabBar };

/**
 * Create an instance of [[OjTabBar]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojTabBar(driver, By.id('my-oj-tab-bar'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojTabBar(driver: DriverLike, by: By): Promise<OjTabBar> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjTabBar
  if (!(webEl instanceof OjTabBar)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-tab-bar>`);
  }
  return webEl;
}

register("oj-tab-bar", OjTabBar);
